#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int64_t sum = 0; for(int i=0;i<N;i++){ int x; scanf("%d", &x); sum += x; }
        int K = N/2;
        if(sum % K != 0){ printf("NO\n"); }
        else if( ((sum / K) & 1LL) == 0 ){ printf("NO\n"); }
        else{ printf("YES\n"); }
    }
    return 0;
}

