import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out = []
    for _ in range(t):
        n = int(next(it))
        s = 0
        for _ in range(n):
            s += int(next(it))
        k = n // 2
        if s % k != 0:
            out.append('NO')
        else:
            q = s // k
            out.append('YES' if q % 2 == 1 else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

